INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Text-Based Video Editing$q$, $q$Edit video by cutting and rearranging an auto-generated transcript instead of scrubbing a timeline manually.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Auto Subtitles & Captions$q$, $q$Automatically generate, style, and burn in or export subtitles in a wide range of languages and formats (SRT, VTT, TXT).$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$AI Avatars$q$, $q$Turn a written script into a talking-head presenter video using a selection of AI avatars and voices.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$AI Translation & Dubbing$q$, $q$Translate video subtitles and audio into dozens of languages, with voice-preserving dubbing for a more natural localized result.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Screen & Webcam Recorder$q$, $q$Record screen, webcam, or both directly in the browser without installing separate recording software.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Magic Cut & Audio Cleanup$q$, $q$Automatically remove filler words, silences, and background noise from recorded footage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Brand Kit$q$, $q$Save brand fonts, colors, and logos to apply consistent styling across videos and team members.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Stock Media Library$q$, $q$Access a built-in library of royalty-free video clips, images, and music to use in projects.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Team Collaboration$q$, $q$Share projects, leave comments, and give multiple editors access to the same workspace.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Video Hosting & Sharing$q$, $q$Host finished videos with a shareable player and basic analytics for tracking views.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Fast, browser-based editing with no software installation required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Text-based editing and auto-subtitles significantly speed up common editing tasks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Broad AI toolset (avatars, translation, dubbing) bundled into one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Simple, low learning curve for non-professional editors and marketing teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Free plan and tiered pricing make it accessible for individuals and small teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Limited manual control compared to professional NLEs like Premiere Pro or Resolve$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Performance issues (buffering, lag) reported on longer or higher-resolution videos$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$AI features such as auto-captions, dubbing, and avatars can require manual correction$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Free plan has meaningful limits (watermark, resolution, caption minutes)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Customer support responsiveness has been inconsistent according to user reviews$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Is VEED free to use?$q$, $q$VEED offers a free plan that supports basic trimming, recording, and a limited amount of auto-captioning per month, but exports include a watermark and are capped at 720p. Paid plans remove the watermark and unlock higher resolutions and usage limits.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Does VEED work without installing any software?$q$, $q$Yes. VEED runs entirely in a web browser, so there is nothing to download or install, and projects are accessible from any device with an internet connection.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$What languages does VEED support for subtitles and dubbing?$q$, $q$VEED supports automatic subtitle generation and translation in a large number of languages, along with AI dubbing in dozens of languages that attempts to preserve the original speaker's voice.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Can teams collaborate on projects in VEED?$q$, $q$Yes, paid plans allow multiple editors to be added to a workspace, with shared brand kits and commenting so teams can review and edit videos together.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Is VEED suitable for professional film or broadcast production?$q$, $q$VEED is designed for speed and accessibility rather than frame-accurate professional post-production, so it's generally better suited to social, marketing, and internal video content than high-end film or broadcast workflows.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Social Media Content Repurposing$q$, $q$Turn long-form recordings like podcasts, webinars, or interviews into short, captioned clips optimized for TikTok, Instagram, and YouTube Shorts.$q$, $q$Social media managers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Sales & Marketing Video Production$q$, $q$Produce branded product demos, ad creatives, and explainer videos quickly using templates, brand kits, and stock media.$q$, $q$Marketing and sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Employee Training & Internal Comms$q$, $q$Create and update onboarding, training, and internal announcement videos using AI avatars and script-based editing instead of re-shooting on camera.$q$, $q$HR, L&D, and internal communications teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Multi-Language Video Localization$q$, $q$Translate and dub existing videos into multiple languages to reach international audiences without re-recording.$q$, $q$Global marketing and localization teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["720p exports with watermark","Up to 30 minutes of auto-captioning per month","Screen and webcam recording","Trim and stitch clips"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Basic$q$, $q$$18/month ($14/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Watermark-free exports","Full HD 1080p exports","Auto subtitles (up to 144 hours/year)","Access to 50,000+ royalty-free assets","Simple brand kit"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Pro$q$, $q$$30/month ($24/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Access to full AI toolset","4K Ultra HD exports","Video translation into 50+ languages","AI avatars (up to 4 hours/year)","Text-to-speech (up to 144 hours/year)","Up to 5 editors"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$Business$q$, $q$$70/month ($59/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Higher usage limits than Pro","Additional seats for larger teams","Priority support","Advanced brand controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$VEED is a browser-based video editing platform founded in London in 2018, built around the idea that anyone should be able to produce polished video content without installing heavyweight desktop software or learning a traditional non-linear editor. Rather than a timeline-first workflow, VEED leans on a text-based and template-driven editing model, letting users trim, caption, and restyle footage largely by editing a transcript or dropping content into pre-built layouts.$q$, $q$Over time VEED has expanded from a simple online trimmer-and-subtitler into a much broader AI video suite: automatic captions, AI avatars that turn scripts into talking-head videos, multi-language dubbing and translation, screen and webcam recording, and generative tools built on top of third-party models. The common thread across all of it is speed — VEED is optimized for creators and teams who need to go from raw footage or a script to a finished, shareable video in minutes rather than hours.$q$, $q$Positioned against both consumer tools like CapCut and professional suites like Premiere Pro or DaVinci Resolve, VEED sits in the middle: more capable and business-oriented than a phone editing app, but far more accessible than a traditional NLE. It is best understood as an AI-first, cloud-native alternative for teams whose priority is volume and turnaround speed over frame-level cinematic control.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$who-veed-is-for$q$, $q$Who VEED Is For$q$, 2, ARRAY[$q$VEED's clearest audience is social media managers, content creators, and marketing teams who need to turn raw footage, webinars, or scripts into short-form, captioned, on-brand video at speed. The subtitle and translation tools in particular are aimed squarely at anyone repurposing long-form content — podcasts, interviews, webinars — into clips for Instagram, TikTok, YouTube Shorts, and LinkedIn.$q$, $q$It also serves internal-facing use cases well: HR, learning-and-development, sales enablement, and customer support teams use VEED to record and caption training videos, product walkthroughs, and onboarding material without pulling in a video production specialist. The AI avatar and text-to-speech features make it possible to generate this kind of content from a script alone, which is valuable for teams that need to update videos frequently but don't want to re-shoot on camera each time.$q$, $q$Small businesses, solo creators, and non-technical marketers who have never used a professional editor are a strong fit too, since VEED's interface trades away deep manual control for guided, template-based workflows. Teams that need lightweight collaboration — commenting, shared brand kits, multiple editors on one workspace — also benefit from VEED being fully browser-based, with nothing to install or sync across machines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Professional video editors and filmmakers who need frame-accurate color grading, advanced VFX, multi-cam sync, or deep audio mixing will find VEED's toolset comparatively shallow. It is not built to replace DaVinci Resolve, Premiere Pro, or Final Cut for high-end production work, and users coming from those tools often describe VEED's manual editing controls as limited by comparison.$q$, $q$Because VEED runs entirely in the browser and processes video in the cloud, users working with very long-form footage, large 4K files, or unreliable internet connections may run into slower uploads, rendering delays, or occasional performance hiccups — a recurring theme in user reviews alongside export queue times on longer projects.$q$, $q$Organizations with strict data residency or privacy requirements around uploading raw video and audio to a third-party cloud service should evaluate VEED's data handling policies carefully before committing. Similarly, teams expecting the free plan to cover serious ongoing production work should note its watermark, resolution, and caption-length limits — the free tier is best suited to occasional or trial use rather than a long-term production workflow.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, VEED offers text-based editing: once footage is transcribed, users can cut, reorder, or delete sections simply by editing the transcript, with the video updating to match. This pairs with automatic subtitle generation across a large number of languages, subtitle styling presets, and export options for burned-in captions or standard SRT/VTT files, plus a built-in screen and webcam recorder for capturing content directly in the browser.$q$, $q$On the AI side, VEED provides AI avatars that convert a script into a talking presenter video, AI voice generation and dubbing that can translate a video into dozens of languages while attempting to preserve the original speaker's voice characteristics, and utility tools like filler-word and silence removal, background noise cleanup, and eye-contact correction for webcam footage.$q$, $q$Rounding out the platform are collaboration and brand features: a shared brand kit for fonts, colors, and logos, multi-editor project access for teams, a library of royalty-free stock video, images, and music, and integrations for publishing or hosting finished videos. Business and Enterprise tiers add higher usage limits, more seats, and priority support on top of the same core toolset.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', $q$the-veed-experience$q$, $q$The VEED Experience$q$, 2, ARRAY[$q$Most reviews agree that VEED's biggest strength is approachability: the interface is clean, the learning curve is short, and the transcript-driven editing model genuinely speeds up common tasks like trimming interviews or captioning a webinar compared to a traditional timeline editor. New users are typically able to produce a captioned, branded video within their first session with little to no onboarding.$q$, $q$The tradeoff shows up around the edges of that simplicity. User feedback across review sites frequently mentions buffering or lag when working with longer videos, occasional inaccuracies in auto-captions or AI dubbing that need manual correction, and export or rendering queues that can feel slow relative to desktop software. Support quality is described as mixed, with some users citing slow response times for account or billing issues.$q$, $q$Overall, VEED tends to earn strong satisfaction from its core audience — social content creators, marketers, and internal comms teams — who value speed and ease of use over granular editing control. Users coming from a professional post-production background, or those with heavy, high-resolution workloads, are more likely to notice its rough edges around performance and precision.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('409ea4dc-896f-4857-8834-ef3e42d8555a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
