INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Multi-network publishing and scheduling$q$, $q$Plan and schedule content across Facebook, Instagram, LinkedIn, X, TikTok, YouTube, Reddit, Pinterest, Snapchat, Threads, Bluesky, Tumblr, and Google Business Profile from one calendar.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Unified engagement inbox$q$, $q$Consolidates comments, mentions, and direct messages from connected profiles into a single queue so teams can respond faster.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Analytics and custom reporting$q$, $q$Tracks performance across channels with dashboards and customizable reports for clients or internal stakeholders.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Social listening$q$, $q$Monitors brand mentions, keywords, and conversations to help teams track sentiment and identify engagement opportunities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Review management$q$, $q$Aggregates and helps respond to customer reviews from connected business profiles in one place.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$DM automation$q$, $q$Automates responses to direct messages at scale, with contact limits that increase by plan tier.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Ask Vista AI assistant$q$, $q$An in-app AI assistant that helps draft captions, replies, and content ideas, with expanded AI training tools on higher plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Vista Page link-in-bio$q$, $q$A customizable landing page tool for consolidating links, available across all plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$White-label and integrations$q$, $q$Higher-tier plans add white-label branding for agencies plus integrations with Zapier, Make, and MCP for connecting to other tools.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Broad network coverage including newer platforms like TikTok, Reddit, Threads, and Bluesky alongside the mainstream channels$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Combines publishing, engagement, listening, reviews, and DM automation in a single subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Plan pricing bundles a set number of users and profiles rather than charging per additional seat$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$14-day free trial with full feature access and no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Built-in AI assistant and AI training tools for content and reply drafting$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$No permanent free plan, only a time-limited trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Interface is English-only, with no localization for other languages currently available$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Some advanced workflow, reporting, and integration features are gated to higher-priced plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Enterprise pricing is custom and not published, requiring a sales conversation for larger needs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Smaller companies with only one or two profiles may find the entry-level plan more than they need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$What is Vista Social used for?$q$, $q$Vista Social is used to plan, schedule, and publish social media content, manage engagement and direct messages, monitor listening and reviews, and analyze performance across multiple social networks from one dashboard.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Does Vista Social offer a free trial?$q$, $q$Yes, Vista Social offers a 14-day free trial with full feature access and no credit card required to start.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$How much does Vista Social cost?$q$, $q$Paid plans start at $79 per month for the Professional tier when billed monthly, with Advanced and Scale plans priced higher and an Enterprise tier available at custom pricing. Annual billing offers a discount of roughly 20%.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Which social networks does Vista Social support?$q$, $q$Vista Social supports Facebook, Instagram, LinkedIn, X, TikTok, YouTube, Reddit, Pinterest, Snapchat, Threads, Bluesky, Tumblr, and Google Business Profile.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Is Vista Social available on mobile?$q$, $q$Yes, Vista Social offers iOS and Android mobile apps in addition to its web dashboard and browser extension.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Agency client management$q$, $q$Agencies manage multiple client social profiles, collaborate on content approvals, and generate branded reports from one account.$q$, $q$Social media agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Cross-platform content scheduling$q$, $q$Marketing teams plan and publish content across a wide mix of established and emerging networks without switching tools.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Customer engagement and reputation management$q$, $q$Teams consolidate comments, messages, and reviews into one inbox to respond to customers faster and monitor brand sentiment.$q$, $q$Community and support managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$AI-assisted content creation$q$, $q$Users draft captions, replies, and content ideas with the Ask Vista assistant to speed up day-to-day content production.$q$, $q$Small business owners and solo marketers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Professional$q$, $q$$79/month (monthly) or $758/year (annual)$q$, $q$Monthly or annual$q$, $q$["15 social profiles","3 users","10,000 DM contacts","Planning and publishing tools","Engagement, listening, and review tools","Vista Page link-in-bio","Ask Vista AI assistant"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Advanced$q$, $q$$149/month (monthly) or $1,430/year (annual)$q$, $q$Monthly or annual$q$, $q$["30 social profiles","6 users","25,000 DM contacts","Advanced planning and workflows","Advanced reporting","Zapier, Make, and MCP integrations","AI training and knowledge tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Scale$q$, $q$$349/month (monthly) or $3,638/year (annual)$q$, $q$Monthly or annual$q$, $q$["70 social profiles","10 users","100,000 DM contacts","White-label setup","Client profile connect","Unlimited AI credits","Premium AI training and knowledge tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, $q$["Unlimited profiles","Unlimited users","Customizable DM contacts","Dedicated account management","Advanced sentiment analysis and brand safety tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Vista Social is a social media management platform built for agencies, marketing teams, and businesses that need to plan, publish, and analyze content across a wide range of networks from a single dashboard. Founded in 2020 by Vitaly Veksler and based in New York, the company positions itself as a modern alternative to older, more rigid social media suites, emphasizing coverage of newer platforms alongside the established ones.$q$, $q$The platform brings together publishing and scheduling, a unified engagement inbox, analytics and custom reporting, social listening, review management, direct message automation, and an employee advocacy module. It supports Facebook, Instagram, LinkedIn, X, TikTok, YouTube, Reddit, Pinterest, Snapchat, Threads, Bluesky, Tumblr, and Google Business Profile, giving teams one place to manage most of the channels a modern brand cares about.$q$, $q$More recently, Vista Social has layered in AI features, including an in-app assistant called Ask Vista and AI training/knowledge tools that help generate captions, respond to messages, and support workflows across its plans. Combined with a link-in-bio tool called Vista Page, the product aims to function as a single command center rather than a point solution for scheduling alone.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$who-vista-social-is-for$q$, $q$Who Vista Social Is For$q$, 2, ARRAY[$q$Vista Social is best suited to social media agencies and in-house marketing teams that manage multiple brands or client accounts and need scheduling, reporting, and collaboration tools that scale across many profiles and users without punitive per-seat pricing. Its tiered plans, which bundle a set number of social profiles and team seats per plan, make it a natural fit for teams that are actively growing their client or brand roster.$q$, $q$It also appeals to teams that want broader network coverage than many competitors offer, particularly those actively posting to Reddit, TikTok, Threads, Bluesky, or Google Business Profile alongside the mainstream platforms. Businesses that want engagement, listening, and review management combined with publishing in one subscription, rather than stitching together several point tools, are a strong match.$q$, $q$Smaller businesses and solo marketers who want an AI assistant to help draft posts and replies, plus a link-in-bio page, may also find value in the lower-tier plans, especially given the 14-day free trial that requires no credit card to start.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need a genuinely free, ongoing plan should look elsewhere, since Vista Social is a paid product with only a time-limited trial rather than a permanent free tier. Very budget-constrained solo creators managing just one or two profiles may find cheaper or free single-purpose scheduling tools better suited to their needs.$q$, $q$Organizations that require a fully localized, non-English interface should also be cautious, as Vista Social's product is currently English-only; users have requested additional language support, but it has not shipped as of this writing.$q$, $q$Large enterprises with deep, custom API integration requirements or highly specialized compliance and governance needs may want to evaluate Vista Social's Enterprise tier closely against dedicated enterprise-grade platforms before committing, since some advanced integration and workflow capabilities are gated to higher-priced plans.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Vista Social offers content planning and publishing across 13+ networks, with collaborative approval workflows, a unified content calendar, and bulk scheduling tools. This is paired with an engagement inbox that consolidates comments, mentions, and messages from connected profiles into one queue for faster response times.$q$, $q$Beyond publishing, the platform includes analytics and customizable reporting, social listening for brand and keyword monitoring, review management for aggregating and responding to customer reviews, and DM automation for handling inbound messages at scale. The Vista Page tool provides a customizable link-in-bio landing page, while the Ask Vista AI assistant helps with caption writing and message replies.$q$, $q$Higher plans add advanced workflows, custom reporting, white-label options for agencies reselling the platform to clients, and integrations with Zapier, Make, and MCP for connecting Vista Social to other business tools, along with an employee advocacy module for encouraging staff to amplify company content.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', $q$the-vista-social-experience$q$, $q$The Vista Social Experience$q$, 2, ARRAY[$q$Vista Social markets itself around ease of setup and day-to-day usability, and it has received G2 recognition in categories such as usability, implementation, and support, according to the company's own materials. New users can start a 14-day trial with full feature access and no credit card required, which lowers the barrier to testing the platform against existing workflows.$q$, $q$Pricing is structured in tiers, Professional, Advanced, Scale, and a custom Enterprise plan, each bundling a set number of social profiles, team seats, and DM contacts rather than charging per additional user, which can make costs more predictable for growing teams. Annual billing carries a roughly 20% discount compared to paying month to month.$q$, $q$Because the platform bundles publishing, engagement, listening, reviews, and AI assistance together, teams switching from a collection of separate tools often experience a period of consolidation as they migrate workflows into Vista Social's dashboard, mobile apps, and browser extension.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('10056aba-b816-4765-8bc7-9b81336ea50d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
